"use strict";parserFactory.register("pawread.com",()=>new PawreadParser);class PawreadParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.baseURI;return[...e.querySelectorAll("div.filtr-item .item-box")].map(e=>this.itemToChapter(e,t))}itemToChapter(e,t){let r=e.getAttribute("onclick"),l="";if(r){let e=r.split("'");e.length>1&&(l=e[1])}if(!l){l=(e.querySelector("a")||e).getAttribute("href")||"",l.startsWith(t)&&(l=l.substring(t.length)),l.endsWith(".html")&&(l=l.substring(0,l.length-5))}return{sourceUrl:t+l+".html",title:e.querySelector(".c_title")?.textContent?.trim()||e.textContent.trim()}}findContent(e){return e.querySelector("#chapter_item")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h3")}findCoverImageUrl(e){let t=e.querySelector(".comic-view [style*=background-image]");return util.extractUrlFromBackgroundImage(t)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("p.txtDesc")]}}